mapper.select:
SELECT ntc_oid, ntc_nm, ntc_cn, ntc_cn_txt, bgng_dt, end_dt, open_yn, use_yn, inq_cnt, reg_id, reg_dt, mdfcn_id, mdfcn_dt, IF( CURDATE() >= DATE(bgng_dt) AND ( end_dt IS NULL OR end_dt = '0000-00-00 00:00:00' OR end_dt = '0000-00-00' OR DATE(end_dt) >= CURDATE() ), 'Y', 'N' ) AS upend_fix_yn FROM ${schema}.ntc
AND ntc_oid = #{ntcOid}
AND ntc_nm LIKE CONCAT('%', #{keyword}, '%')
AND reg_dt >= #{regDtFrom} AND reg_dt < DATE_ADD(#{regDtTo}, INTERVAL 1 DAY)
AND open_yn = #{openYn}
ORDER BY ntc_oid DESC

mapper.update:
UPDATE ${schema}.ntc
ntc_nm = #{ntcNm}, ntc_cn = #{ntcCn}, ntc_cn_txt = #{ntcCnTxt}, bgng_dt = #{bgngDt}, end_dt = #{endDt}, upend_fix_yn = #{upendFixYn}, open_yn = #{openYn}, mdfcn_id = #{mdfcnId}, use_yn = 'Y'
WHERE ntc_oid = #{ntcOid}

UPDATE ${schema}.ntc
SET inq_cnt = inq_cnt + 1
WHERE ntc_oid = #{ntcOid}

mapper.delete:
UPDATE ${schema}.ntc
SET use_yn = 'N',
	mdfcn_id = #{mdfcnId}
WHERE ntc_oid = #{ntcOid}
